import Link from "next/link";
import { getAllConcepts } from "../lib/content";

export default function HomePage({ concepts }) {
  return (
    <main style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>Concepts</h1>

        {concepts.length === 0 ? (
          <p style={styles.empty}>No concepts found.</p>
        ) : (
          <ul style={styles.list}>
            {concepts.map((concept) => (
              <li key={concept.slug} style={styles.item}>
                <Link href={`/concept/${concept.slug}`} style={styles.link}>
                  {concept.title || concept.slug}
                </Link>
                <p style={styles.summary}>{concept.summary || ""}</p>
              </li>
            ))}
          </ul>
        )}
      </div>
    </main>
  );
}

export function getStaticProps() {
  return {
    props: {
      concepts: getAllConcepts()
    }
  };
}

const styles = {
  page: {
    padding: "40px 20px",
    fontFamily: "Arial, sans-serif"
  },
  container: {
    maxWidth: "640px",
    margin: "0 auto"
  },
  title: {
    marginTop: 0,
    marginBottom: "24px"
  },
  list: {
    padding: 0,
    margin: 0,
    listStyle: "none"
  },
  item: {
    marginBottom: "20px"
  },
  link: {
    color: "#0f172a",
    fontWeight: "bold",
    textDecoration: "none"
  },
  summary: {
    marginTop: "6px",
    marginBottom: 0,
    lineHeight: 1.6
  },
  empty: {
    margin: 0
  }
};
